function feature(id, title, desc, acceptance, specTitle) {
  return { id, title, desc, status: 'todo', priority: id === 'F4' ? 'mid' : 'high', acceptance: [{ text: acceptance, done: false }], specs: [{ title: specTitle, desc, acceptance: [{ text: acceptance, done: false }] }] };
}

function sot(config, lang) {
  const ko = lang === 'ko';
  const c = config[lang];
  const labels = ko
    ? { r1: '접수와 현황 조회', r2: '처리와 운영 분석', p1: '현황 대시보드', p2: '요청·등록 상세', p3: '처리 작업 공간', p4: '운영 리포트', accept: '사용자는 필요한 정보를 입력하고 현재 상태를 확인할 수 있다.' }
    : { r1: 'Intake and status lookup', r2: 'Processing and operations analysis', p1: 'Overview dashboard', p2: 'Request or record detail', p3: 'Processing workspace', p4: 'Operations report', accept: 'Users can provide required context and view the current state.' };
  const f1 = feature('F1', c.entry, c.solution, labels.accept, ko ? '필수 정보와 유효성 검증' : 'Required context and validation');
  const f2 = feature('F2', c.record, c.problem, labels.accept, ko ? '상태·이력 조회' : 'State and history lookup');
  const f3 = feature('F3', c.process, c.solution, ko ? '처리 담당자와 상태 변경 이력이 기록된다.' : 'Processing ownership and state-change history are retained.', ko ? '처리 정책과 이력' : 'Processing policy and history');
  const f4 = feature('F4', c.report, c.goal, ko ? '운영자는 기간과 분류 기준으로 지표를 필터링할 수 있다.' : 'Operators can filter metrics by period and category.', ko ? '운영 지표 집계' : 'Operations metrics');
  return {
    schemaVersion: '1.0', title: c.title, lang,
    prd: {
      oneLiner: c.solution, goal: c.goal, whyNow: c.problem, category: ko ? '사내 운영 시스템' : 'Internal operations system', platforms: [ko ? '웹' : 'Web'],
      problem: c.problem, solution: c.solution, alternatives: ko ? '이메일, 메신저, 스프레드시트, 수동 대장' : 'Email, chat, spreadsheets, and manual ledgers', differentiator: ko ? '요청·처리·운영 데이터를 하나의 연결된 기준으로 관리한다.' : 'Manage intake, processing, and operations data as one connected source of truth.',
      targets: [{ name: c.user, role: ko ? '요청자·실무 사용자' : 'Requester and operational user', needs: ko ? '필요한 업무를 빠르게 등록하고 상태를 알고 싶다.' : 'Quickly register needed work and know its status.', pain: c.problem }, { name: c.operator, role: ko ? '운영 관리자' : 'Operations administrator', needs: ko ? '처리 우선순위와 이력을 관리하고 지표를 확인하고 싶다.' : 'Manage priority and history and review operations metrics.', pain: c.problem }],
      scenarios: [{ text: ko ? `${c.user}는 ${c.entry}을(를) 완료하고 진행 상태를 확인한다.` : `${c.user} completes ${c.entry.toLowerCase()} and checks progress.`, start: 'P1' }, { text: ko ? `${c.operator}는 ${c.report}을(를) 검토한다.` : `${c.operator} reviews ${c.report.toLowerCase()}.`, start: 'P4' }],
      northStar: ko ? '기한 내 완료된 운영 요청 비율' : 'Share of operations requests completed on time',
      kpis: [{ name: ko ? '기한 내 처리 비율' : 'On-time processing rate', target: c.goal, baseline: ko ? '측정 전' : 'Not measured', method: ko ? '완료 이력과 목표 기한을 기준으로 월별 집계' : 'Monthly aggregation of completion history against target dates', refs: ['F3'] }, { name: ko ? '운영 가시성' : 'Operations visibility', target: ko ? '핵심 요청 100% 추적' : '100% of key requests tracked', baseline: ko ? '측정 전' : 'Not measured', method: ko ? '등록된 요청과 운영 리포트의 연결 비율' : 'Share of registered requests connected to operations reporting', refs: ['F4'] }],
      inScope: [c.entry, c.record, c.process, c.report], nonGoals: ko ? ['외부 고객 포털', '회계·급여 등 인접 시스템 전체 대체'] : ['External customer portal', 'Replacing adjacent systems such as accounting or payroll'],
      assumptions: ko ? ['사용자와 조직 정보는 사내 SSO에서 제공된다.', '운영 정책과 분류 기준을 담당자가 관리한다.'] : ['User and organization data are available through company SSO.', 'Operators manage policy and classification criteria.'],
      risks: ko ? ['초기 분류와 운영 기준이 불명확하면 잘못된 처리로 이어질 수 있다.', '기준 데이터가 갱신되지 않으면 운영 신뢰가 떨어진다.'] : ['Weak initial classification can cause incorrect processing.', 'Stale source data can reduce operational trust.'],
      openQuestions: ko ? ['긴급 처리 기준과 승인 절차는 무엇인가?', '완료 후 검증과 재오픈 기준은 무엇인가?'] : ['What defines urgent processing and approval?', 'What are the post-completion verification and reopen rules?'],
      constraints: ko ? ['상태·담당자·우선순위 변경은 감사 로그로 남긴다.', '접근 권한은 역할별로 제한한다.'] : ['State, owner, and priority changes require audit logs.', 'Access is limited by role.']
    },
    requirements: [
      { id: 'R1', title: labels.r1, desc: c.problem, status: 'todo', priority: 'high', acceptance: [{ text: labels.accept, done: false }], features: [f1, f2] },
      { id: 'R2', title: labels.r2, desc: c.solution, status: 'todo', priority: 'high', acceptance: [{ text: labels.accept, done: false }], features: [f3, f4] }
    ],
    ia: { sections: [{ id: 'S1', title: labels.r1, pages: [{ id: 'P1', title: labels.p1, type: 'top', refs: ['F1', 'F1:0'], children: [] }, { id: 'P2', title: labels.p2, type: 'page', refs: ['F2', 'F2:0'], children: [] }] }, { id: 'S2', title: labels.r2, pages: [{ id: 'P3', title: labels.p3, type: 'top', refs: ['F3', 'F3:0'], children: [] }, { id: 'P4', title: labels.p4, type: 'page', refs: ['F4', 'F4:0'], children: [] }] }] },
    flow: { start: 'P1', transitions: [{ from: 'P1', to: 'P2', ref: 'F1' }, { from: 'P2', to: 'P3', ref: 'F2' }, { from: 'P3', to: 'P4', ref: 'F3' }, { from: 'P4', to: 'P1', ref: 'F4' }] }
  };
}

function locale(config, lang) {
  const ko = lang === 'ko'; const c = config[lang]; const slug = config.slug;
  const baseTitle = ko ? `${c.title} PRD 템플릿 | 무료 기획서` : `${c.title} PRD Template`;
  const included = [c.entry, c.record, c.process, c.report];
  const image = (kind) => `${slug}-${kind}-${lang}.png`;
  return { title: baseTitle, metaDescription: ko ? `무료 ${c.title} PRD 템플릿입니다. ${included.join(', ')}을 연결한 기능 명세서·IA·유저 플로우를 다운로드하세요.` : `A free ${c.title} PRD template with connected ${included.join(', ').toLowerCase()}, feature specifications, information architecture, and user flows.`, summary: ko ? `${c.title} PRD 템플릿으로, ${included.join(', ')}을 연결한 실제 SOT 기반 기획서입니다.` : `A real SOT-based ${c.title} PRD template connecting ${included.join(', ').toLowerCase()}.`, audience: ko ? `${c.user}와 ${c.operator}를 위한 사내 운영 시스템을 설계하는 팀` : `Teams designing an internal operations system for ${c.user.toLowerCase()} and ${c.operator.toLowerCase()}`, included, keywords: ko ? [`${c.title} PRD`, `${c.title} 기획서`, `${c.title} 기능 명세서`, '시스템 구축', 'VibeSpec'] : [`${c.title} PRD template`, `${c.title} requirements`, `${c.title} feature specification`, 'internal operations system', 'VibeSpec'], images: [{ filename: image('prd'), alt: ko ? `${c.title}의 목표, 문제, 사용자 페르소나를 보여 주는 VibeSpec PRD 화면` : `${c.title} PRD showing product goals, problem context, and operational personas`, caption: ko ? '제품 문제와 운영 목표를 하나의 PRD로 연결합니다.' : 'Connect the operational problem and measurable outcomes in one PRD.', tags: [ko ? `${c.title} PRD` : `${c.title} PRD`, ko ? '운영 목표' : 'operations goals'] }, { filename: image('spec'), alt: ko ? `${c.title}의 요구사항, 기능, 상세 기능, 수용 기준을 보여 주는 기능 명세 화면` : `${c.title} feature specification with requirements, detailed capabilities, and acceptance criteria`, caption: ko ? '요구사항을 기능과 수용 기준까지 추적 가능한 형태로 정리합니다.' : 'Trace requirements through features and acceptance criteria.', tags: [ko ? '기능 명세서' : 'feature specification', ko ? '수용 기준' : 'acceptance criteria'] }, { filename: image('flow'), alt: ko ? `${c.title}의 현황, 요청, 처리, 운영 리포트를 연결한 사용자 흐름도` : `${c.title} user flow connecting overview, request, processing, and operations reporting`, caption: ko ? '실무 사용자와 운영자의 실제 흐름을 화면 단위로 검토합니다.' : 'Review real user and operator workflow as connected screens.', tags: [ko ? '유저 플로우' : 'user flow', ko ? '운영 워크플로우' : 'operations workflow'] }], htmlDownloadUrl: `/downloads/${slug}-prd-template-${lang}.html`, demoUrl: `/demos/${slug}/${lang}/`, downloadUrl: `https://raw.githubusercontent.com/chjoel0621/vibespec/main/demo/${slug}.${lang}.sot.json`, githubFileUrl: `https://github.com/chjoel0621/vibespec/blob/main/demo/${slug}.${lang}.sot.json` };
}

const allSystems = [...systems, ...industryCrmSystems, ...coreItSystems, ...coreItSystems2];

for (const config of allSystems) {
  for (const lang of ['ko', 'en']) await writeFile(resolve(vibeRoot, 'demo', `${config.slug}.${lang}.sot.json`), JSON.stringify(sot(config, lang), null, 2) + '\n');
}
await mkdir(resolve(marketingRoot, 'content'), { recursive: true });
await writeFile(resolve(marketingRoot, 'content', 'batch-templates.json'), JSON.stringify({ templates: allSystems.map((config) => ({ slug: config.slug, published: '2026-07-20', locales: { ko: locale(config, 'ko'), en: locale(config, 'en') } })) }, null, 2) + '\n');
console.log(`Generated ${allSystems.length * 2} SOT files and ${allSystems.length} template records.`);
